VALUES
  ('promotion-53250add-moex-00088', 'promotion-53250add', 'promotion-53250add-moex-112-9b7ab1bb', 'sub-promotion-53250add-03', NULL, 'single_choice', '關於親屬之種類與親等之計算，下列敘述何者正確？', '["稱直系血親者，僅係指與己身出於同源之法定血親", "稱姻親者，謂血親之配偶、配偶之血親及配偶之血親之配偶", "血親之配偶，其親系與親等之計算，皆從其與旁系血親之配偶之親系與親等", "姻親關係，因具法定分居事由而消滅"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:46+00:00", "source_pdf_sha1": "0635b758199f", "answer_pdf_sha1": "cdba98d79113", "source_family": "moex-gov-tw", "moex": {"exam_code": "112170", "c": "137", "s": "0501", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法", "year": "112", "exam_name": "112年公務人員升官等考試、112年關務人員升官等考試、112年交通事業鐵路人員升資考試、112年交通事業港務人員升資考試", "original_question_number": 20, "answer_corrected": false, "flags": [], "civil_slug": "promotion", "civil_category": "智慧財產行政"}'::jsonb, NULL),
  ('promotion-53250add-moex-00089', 'promotion-53250add', 'promotion-53250add-moex-112-9b7ab1bb', 'sub-promotion-53250add-03', NULL, 'single_choice', '甲乙結婚後，乙與丙合意性交，甲發現後持刀殺丙未遂。甲因而被判處有期徒刑三年確定。下列 敘述何者錯誤？', '["甲乙如經協議離婚，甲並無贍養費請求權", "甲服刑期滿後，再以乙與丙合意性交訴請離婚，已逾除斥期間", "甲乙就難以維持婚姻均應負責，故雙方均不得請求離婚", "乙知悉甲被判刑確定後已逾一年者，不得請求離婚"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:46+00:00", "source_pdf_sha1": "0635b758199f", "answer_pdf_sha1": "cdba98d79113", "source_family": "moex-gov-tw", "moex": {"exam_code": "112170", "c": "137", "s": "0501", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法", "year": "112", "exam_name": "112年公務人員升官等考試、112年關務人員升官等考試、112年交通事業鐵路人員升資考試、112年交通事業港務人員升資考試", "original_question_number": 21, "answer_corrected": false, "flags": [], "civil_slug": "promotion", "civil_category": "智慧財產行政"}'::jsonb, NULL),
  ('promotion-53250add-moex-00090', 'promotion-53250add', 'promotion-53250add-moex-112-9b7ab1bb', 'sub-promotion-53250add-03', NULL, 'single_choice', '未婚之乙女與已婚之甲男發生性行為，致生一子丁。甲男為維持婚姻，逃避之。甲在乙女之兄長 丙持刀脅迫下認領丁。關於甲之認領，下列敘述何者正確？', '["認領有效且不得撤銷", "認領無效", "認領得撤銷", "須得甲男之妻承認，始生效力"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:46+00:00", "source_pdf_sha1": "0635b758199f", "answer_pdf_sha1": "cdba98d79113", "source_family": "moex-gov-tw", "moex": {"exam_code": "112170", "c": "137", "s": "0501", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法", "year": "112", "exam_name": "112年公務人員升官等考試、112年關務人員升官等考試、112年交通事業鐵路人員升資考試、112年交通事業港務人員升資考試", "original_question_number": 22, "answer_corrected": false, "flags": [], "civil_slug": "promotion", "civil_category": "智慧財產行政"}'::jsonb, NULL),
  ('promotion-53250add-moex-00091', 'promotion-53250add', 'promotion-53250add-moex-112-9b7ab1bb', 'sub-promotion-53250add-03', NULL, 'single_choice', '下列關於遺囑撤回之敘述，何者正確？', '["遺囑人得隨時以自書或錄影錄音之遺囑方式，撤回遺囑之全部或一部，經全體遺囑受益人同意 後，其撤回始生效力", "以自書方式立遺囑者，其發現前後遺囑有相牴觸之情狀，立遺囑人之配偶或直系血親卑親屬應 共同聲請刑事鑑定機關進行確認", "遺囑人於為遺囑後所為之行為與遺囑有相牴觸者，其牴觸部分，遺囑視為撤回", "遺囑人故意塗銷遺囑之特定部分，或在遺囑上記明特定部分廢棄者，該部分之遺囑視為撤回， 並應經全體遺囑受益人見證且簽名之"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:46+00:00", "source_pdf_sha1": "0635b758199f", "answer_pdf_sha1": "cdba98d79113", "source_family": "moex-gov-tw", "moex": {"exam_code": "112170", "c": "137", "s": "0501", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法", "year": "112", "exam_name": "112年公務人員升官等考試、112年關務人員升官等考試、112年交通事業鐵路人員升資考試、112年交通事業港務人員升資考試", "original_question_number": 23, "answer_corrected": false, "flags": [], "civil_slug": "promotion", "civil_category": "智慧財產行政"}'::jsonb, NULL),
  ('promotion-53250add-moex-00092', 'promotion-53250add', 'promotion-53250add-moex-112-9b7ab1bb', 'sub-promotion-53250add-03', NULL, 'single_choice', '下列關於繼承回復請求權之敘述，何者正確？', '["繼承回復請求權與個別物上請求權係屬真正繼承人分別獨立而併存之權利", "繼承回復請求權於時效完成後，真正繼承人喪失其合法取得之繼承權", "繼承權被侵害者，自命繼承人之被告或其法定代理人得請求回復之", "繼承回復請求權，自知悉被侵害之時起，十年間不行使而消滅"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:46+00:00", "source_pdf_sha1": "0635b758199f", "answer_pdf_sha1": "cdba98d79113", "source_family": "moex-gov-tw", "moex": {"exam_code": "112170", "c": "137", "s": "0501", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法", "year": "112", "exam_name": "112年公務人員升官等考試、112年關務人員升官等考試、112年交通事業鐵路人員升資考試、112年交通事業港務人員升資考試", "original_question_number": 24, "answer_corrected": false, "flags": [], "civil_slug": "promotion", "civil_category": "智慧財產行政"}'::jsonb, NULL),
  ('promotion-53250add-moex-00093', 'promotion-53250add', 'promotion-53250add-moex-112-9b7ab1bb', 'sub-promotion-53250add-03', NULL, 'single_choice', '甲男乙女為夫妻，依法約定採夫妻分別財產制。甲乙生有一女丙。甲乙於民國（下同）105 年間 依法收養已婚之丁為養子時，丁與其妻A生有一子B，B年5歲。於108年間，丁與A再生一女', '["", "", "丁於110年1月10日，與甲、乙共同出遊，遭意外，丁當日死亡，甲於意外後3日死亡，乙 重傷。甲之好友為庚，丁之好友為辛，甲與丁生前均立遺囑，分別對庚及辛為遺贈。下列敘述何 者正確？", ""]'::jsonb, 2, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:46+00:00", "source_pdf_sha1": "0635b758199f", "answer_pdf_sha1": "cdba98d79113", "source_family": "moex-gov-tw", "moex": {"exam_code": "112170", "c": "137", "s": "0501", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法", "year": "112", "exam_name": "112年公務人員升官等考試、112年關務人員升官等考試、112年交通事業鐵路人員升資考試、112年交通事業港務人員升資考試", "original_question_number": 25, "answer_corrected": false, "flags": ["incomplete_options"], "civil_slug": "promotion", "civil_category": "智慧財產行政"}'::jsonb, NULL),
  ('promotion-53250add-moex-00094', 'promotion-53250add', 'promotion-53250add-moex-112-3082b5f1', 'sub-promotion-53250add-04', NULL, 'essay', '單行道、速限、禁鳴喇叭、禁止停車或禁止超車等交通標誌與標線之法
律性質為何？請依現制及實務說明之。（25 分）', '[]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:46+00:00", "source_pdf_sha1": "b796954d584f", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "112170", "c": "137", "s": "0408", "q": "1"}, "raw_section_label": "甲、申論題部分", "subject": "行政法", "year": "112", "exam_name": "112年公務人員升官等考試、112年關務人員升官等考試、112年交通事業鐵路人員升資考試、112年交通事業港務人員升資考試", "original_question_number": "一", "answer_corrected": false, "flags": [], "civil_slug": "promotion", "civil_category": "智慧財產行政"}'::jsonb, NULL),
  ('promotion-53250add-moex-00095', 'promotion-53250add', 'promotion-53250add-moex-112-3082b5f1', 'sub-promotion-53250add-04', NULL, 'essay', '衛生福利部為有效執行食品安全衛生管理法第 28 條第 1 項、第 2 項禁
止食品標示、宣傳或廣告不實、誇張、易生誤解或宣稱醫療效能之規定，
依同法第28 條第 4 項規定：「第一項不實、誇張或易生誤解與第二項醫
療效能之認定基準、宣傳或廣告之內容、方式及其他應遵行事項之準則，
由中央主管機關定之。」所訂定之「食品及相關產品標示宣傳廣告涉及
不實誇張易生誤解或醫療效能認定準則」，請說明本準則之法律性質、意
涵及效力。（25分）', '[]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:46+00:00", "source_pdf_sha1": "b796954d584f", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "112170", "c": "137", "s": "0408", "q": "1"}, "raw_section_label": "甲、申論題部分", "subject": "行政法", "year": "112", "exam_name": "112年公務人員升官等考試、112年關務人員升官等考試、112年交通事業鐵路人員升資考試、112年交通事業港務人員升資考試", "original_question_number": "二", "answer_corrected": false, "flags": [], "civil_slug": "promotion", "civil_category": "智慧財產行政"}'::jsonb, NULL),
  ('promotion-53250add-moex-00096', 'promotion-53250add', 'promotion-53250add-moex-112-3082b5f1', 'sub-promotion-53250add-04', NULL, 'single_choice', '關於行政法規新舊法適用，下列敘述何者錯誤？', '["人民聲請許可案件處理程序終結前，據以准許之法規變更者，原則上適用新法規", "人民聲請許可案件處理程序終結前，舊法規有利於當事人而新法規未廢除或禁止所聲請之事項 者，適用舊法規", "新修正之普通法應優先於舊的特別法適用", "違法行為後、裁處前法律變更，適用最有利於受處罰者之規定"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:46+00:00", "source_pdf_sha1": "b796954d584f", "answer_pdf_sha1": "403e55525a12", "source_family": "moex-gov-tw", "moex": {"exam_code": "112170", "c": "137", "s": "0408", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政法", "year": "112", "exam_name": "112年公務人員升官等考試、112年關務人員升官等考試、112年交通事業鐵路人員升資考試、112年交通事業港務人員升資考試", "original_question_number": 1, "answer_corrected": false, "flags": [], "civil_slug": "promotion", "civil_category": "智慧財產行政"}'::jsonb, NULL),
  ('promotion-53250add-moex-00097', 'promotion-53250add', 'promotion-53250add-moex-112-3082b5f1', 'sub-promotion-53250add-04', NULL, 'single_choice', '關於依法行政原則，下列敘述何者錯誤？', '["依法行政係指行政必須依據制定法令而為之，並未受一般法律原理原則之拘束", "依法行政原則可再區分為法律保留原則與法律優位原則", "若以法規命令作為行政之依據，則該法規命令應有具體明確之法律授權", "縱然法律規範密度較寬鬆之給付行政，倘涉及公共利益之重大事項者，仍應受法律保留原則之 拘束 11030、11730 12330、12530 12830、13030 13130 14330、14530 30130、70130 71130"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:46+00:00", "source_pdf_sha1": "b796954d584f", "answer_pdf_sha1": "403e55525a12", "source_family": "moex-gov-tw", "moex": {"exam_code": "112170", "c": "137", "s": "0408", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政法", "year": "112", "exam_name": "112年公務人員升官等考試、112年關務人員升官等考試、112年交通事業鐵路人員升資考試、112年交通事業港務人員升資考試", "original_question_number": 2, "answer_corrected": false, "flags": [], "civil_slug": "promotion", "civil_category": "智慧財產行政"}'::jsonb, NULL)
